/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering: maps NotificationType to structured email templates
 * - Recipient resolution: validates and resolves email recipients
 * - Configurable sender, provider, and retry behavior
 * - In-memory transport for testing; swap send internals for real providers (SendGrid, SES, etc.)
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address. */
  from: string;
  /** Email provider name (for logging/identification). */
  provider: string;
  /** Maximum retry attempts for failed sends (default: 0). */
  maxRetries?: number;
  /** Optional reply-to address. */
  replyTo?: string;
}

export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  body: string;
  htmlBody: string;
  sentAt: Date;
  metadata?: Record<string, string>;
}

interface EmailTemplate {
  subject: (payload: NotificationPayload) => string;
  textBody: (payload: NotificationPayload) => string;
  htmlBody: (payload: NotificationPayload) => string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Built-in email templates keyed by NotificationType.
 */
const DEFAULT_TEMPLATES: Record<NotificationType, EmailTemplate> = {
  'order-confirmation': {
    subject: (p) => p.subject,
    textBody: (p) => p.body,
    htmlBody: (p) => {
      const lines = p.body.split('. ');
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        '<h2 style="color: #2563eb;">Order Confirmation</h2>',
        `<p>${escapeHtml(lines[0] ?? '')}.</p>`,
        lines.length > 1
          ? `<p style="color: #6b7280;">${escapeHtml(lines.slice(1).join('. '))}</p>`
          : '',
        '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
        '<p style="font-size: 12px; color: #9ca3af;">Thank you for your order.</p>',
        '</div>',
      ].join('\n');
    },
  },
  'order-status-update': {
    subject: (p) => p.subject,
    textBody: (p) => p.body,
    htmlBody: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h2 style="color: #2563eb;">Order Status Update</h2>',
      `<p>${escapeHtml(p.body)}</p>`,
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="font-size: 12px; color: #9ca3af;">You are receiving this because you placed an order with us.</p>',
      '</div>',
    ].join('\n'),
  },
  'welcome': {
    subject: (p) => p.subject,
    textBody: (p) => p.body,
    htmlBody: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h2 style="color: #2563eb;">Welcome!</h2>',
      `<p>${escapeHtml(p.body)}</p>`,
      '<p>Get started by exploring your dashboard.</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="font-size: 12px; color: #9ca3af;">TaskFlow Pro</p>',
      '</div>',
    ].join('\n'),
  },
  'account-updated': {
    subject: (p) => p.subject,
    textBody: (p) => p.body,
    htmlBody: (p) => [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h2 style="color: #2563eb;">Account Updated</h2>',
      `<p>${escapeHtml(p.body)}</p>`,
      '<p>If you did not make this change, please contact support immediately.</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="font-size: 12px; color: #9ca3af;">TaskFlow Pro</p>',
      '</div>',
    ].join('\n'),
  },
};

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private templates: Map<NotificationType, EmailTemplate> = new Map();
  private recipientResolver: ((recipient: string) => string | null) | null = null;

  constructor(private config: EmailConfig) {
    // Load default templates
    for (const [type, template] of Object.entries(DEFAULT_TEMPLATES)) {
      this.templates.set(type as NotificationType, template);
    }
  }

  /**
   * Register a custom email template for a notification type.
   * Overrides the default template if one exists.
   */
  registerTemplate(type: NotificationType, template: EmailTemplate): void {
    this.templates.set(type, template);
  }

  /**
   * Set a recipient resolver function.
   * The resolver maps a recipient identifier (e.g., user ID) to an email address.
   * Return null to indicate the recipient cannot be resolved.
   */
  setRecipientResolver(resolver: (recipient: string) => string | null): void {
    this.recipientResolver = resolver;
  }

  /**
   * Resolve a recipient identifier to an email address.
   * If the recipient is already a valid email, it is returned as-is.
   * Otherwise, the recipient resolver is consulted.
   */
  resolveRecipient(recipient: string): string | null {
    if (EMAIL_REGEX.test(recipient)) {
      return recipient;
    }
    if (this.recipientResolver) {
      return this.recipientResolver(recipient);
    }
    return null;
  }

  /**
   * Render an email from a notification payload using the registered template.
   * Returns the rendered subject, text body, and HTML body.
   */
  renderTemplate(payload: NotificationPayload): { subject: string; textBody: string; htmlBody: string } {
    const template = this.templates.get(payload.type);
    if (!template) {
      // Fallback: use payload fields directly
      return {
        subject: payload.subject,
        textBody: payload.body,
        htmlBody: `<p>${escapeHtml(payload.body)}</p>`,
      };
    }
    return {
      subject: template.subject(payload),
      textBody: template.textBody(payload),
      htmlBody: template.htmlBody(payload),
    };
  }

  /**
   * Send an email notification.
   * Resolves the recipient, renders the template, and delivers the email.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolvedRecipient = this.resolveRecipient(payload.recipient);

    if (!resolvedRecipient) {
      this.logger.warn(
        `Cannot resolve recipient "${payload.recipient}" for notification ${payload.id}`,
      );
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: `Invalid or unresolvable recipient: ${payload.recipient}`,
        timestamp: new Date(),
      };
    }

    const rendered = this.renderTemplate(payload);

    let lastError: string | undefined;
    const maxAttempts = (this.config.maxRetries ?? 0) + 1;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        const email: SentEmail = {
          to: resolvedRecipient,
          from: this.config.from,
          subject: rendered.subject,
          body: rendered.textBody,
          htmlBody: rendered.htmlBody,
          sentAt: new Date(),
          metadata: payload.metadata,
        };

        this.sentEmails.push(email);

        this.logger.info(
          `Email sent via ${this.config.provider} to ${resolvedRecipient}: ${rendered.subject}`,
        );

        return {
          success: true,
          notificationId: payload.id,
          channel: this.channel,
          timestamp: email.sentAt,
        };
      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `Email send attempt ${attempt}/${maxAttempts} failed for ${payload.id}: ${lastError}`,
        );
      }
    }

    return {
      success: false,
      notificationId: payload.id,
      channel: this.channel,
      error: `Failed after ${maxAttempts} attempt(s): ${lastError}`,
      timestamp: new Date(),
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter({
      from: 'noreply@taskflow.com',
      provider: 'test',
    });
  });

  describe('channel', () => {
    it('should report email as the channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('send', () => {
    it('should send an email successfully for a valid recipient', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('email');
      expect(result.timestamp).toBeInstanceOf(Date);
    });

    it('should store the sent email with rendered fields', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('noreply@taskflow.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]?.body).toContain('Widget x2');
      expect(sent[0]?.htmlBody).toContain('<h2');
      expect(sent[0]?.htmlBody).toContain('Order Confirmation');
    });

    it('should fail for an unresolvable recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or unresolvable recipient');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should preserve metadata in sent email', async () => {
      const payload = makePayload({ metadata: { orderId: 'order-1' } });
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.metadata).toEqual({ orderId: 'order-1' });
    });
  });

  describe('recipient resolution', () => {
    it('should pass through valid email addresses', () => {
      expect(adapter.resolveRecipient('alice@example.com')).toBe('alice@example.com');
    });

    it('should return null for non-email without resolver', () => {
      expect(adapter.resolveRecipient('user-123')).toBeNull();
    });

    it('should use the recipient resolver for non-email identifiers', () => {
      adapter.setRecipientResolver((id) => {
        const users: Record<string, string> = {
          'user-1': 'alice@example.com',
          'user-2': 'bob@example.com',
        };
        return users[id] ?? null;
      });

      expect(adapter.resolveRecipient('user-1')).toBe('alice@example.com');
      expect(adapter.resolveRecipient('user-2')).toBe('bob@example.com');
      expect(adapter.resolveRecipient('user-99')).toBeNull();
    });

    it('should send successfully when resolver maps a user ID to email', async () => {
      adapter.setRecipientResolver((id) =>
        id === 'user-1' ? 'alice@example.com' : null,
      );

      const result = await adapter.send(makePayload({ recipient: 'user-1' }));
      expect(result.success).toBe(true);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.to).toBe('alice@example.com');
    });
  });

  describe('template rendering', () => {
    it('should render order-confirmation template with HTML', () => {
      const rendered = adapter.renderTemplate(makePayload());

      expect(rendered.subject).toBe('Order Confirmation: order-1');
      expect(rendered.textBody).toContain('Widget x2');
      expect(rendered.htmlBody).toContain('<h2');
      expect(rendered.htmlBody).toContain('Order Confirmation');
      expect(rendered.htmlBody).toContain('Thank you for your order');
    });

    it('should render welcome template', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          type: 'welcome',
          subject: 'Welcome to TaskFlow Pro!',
          body: 'Hi Alice, welcome to TaskFlow Pro. Your account has been created.',
        }),
      );

      expect(rendered.subject).toBe('Welcome to TaskFlow Pro!');
      expect(rendered.htmlBody).toContain('Welcome!');
      expect(rendered.htmlBody).toContain('Get started');
    });

    it('should render order-status-update template', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          type: 'order-status-update',
          subject: 'Order Update: order-1',
          body: 'Your order status has changed from pending to confirmed.',
        }),
      );

      expect(rendered.htmlBody).toContain('Order Status Update');
      expect(rendered.htmlBody).toContain('pending');
      expect(rendered.htmlBody).toContain('confirmed');
    });

    it('should render account-updated template with security warning', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          type: 'account-updated',
          subject: 'Account Updated',
          body: 'Your account has been updated. Changed fields: name, email.',
        }),
      );

      expect(rendered.htmlBody).toContain('Account Updated');
      expect(rendered.htmlBody).toContain('contact support');
    });

    it('should escape HTML entities in body content', () => {
      const rendered = adapter.renderTemplate(
        makePayload({ body: '<script>alert("xss")</script>' }),
      );

      expect(rendered.htmlBody).not.toContain('<script>');
      expect(rendered.htmlBody).toContain('&lt;script&gt;');
    });

    it('should allow registering custom templates', () => {
      adapter.registerTemplate('welcome', {
        subject: () => 'Custom Welcome',
        textBody: (p) => `Custom: ${p.body}`,
        htmlBody: (p) => `<b>Custom: ${p.body}</b>`,
      });

      const rendered = adapter.renderTemplate(
        makePayload({ type: 'welcome', body: 'hello' }),
      );

      expect(rendered.subject).toBe('Custom Welcome');
      expect(rendered.textBody).toBe('Custom: hello');
      expect(rendered.htmlBody).toBe('<b>Custom: hello</b>');
    });
  });

  describe('sent email management', () => {
    it('should return a copy of sent emails', async () => {
      await adapter.send(makePayload());
      const emails = adapter.getSentEmails();
      emails.pop();
      expect(adapter.getSentEmails()).toHaveLength(1);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should accumulate multiple sent emails', async () => {
      await adapter.send(makePayload({ id: 'notif-0001' }));
      await adapter.send(makePayload({ id: 'notif-0002', recipient: 'bob@example.com' }));

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[1]?.to).toBe('bob@example.com');
    });
  });

  describe('retry behavior', () => {
    it('should default to no retries', async () => {
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
    });
  });
});

